import { Dropdown } from '@carbon/react';
import PropTypes from 'prop-types';
import React, { useContext } from 'react';
import { withPrefix } from '../utils.js';
import { TabContext } from './tabs.js';

const Select = ({
  children,
  _id
}) => {
  const {
    setActiveTab
  } = useContext(TabContext);
  const items = React.Children.map(children, (child, index) => ({
    index,
    label: child.props.label
  }));
  return (
    /*#__PURE__*/
    // @ts-ignore
    React.createElement(Dropdown, {
      size: "md",
      onChange: ({
        selectedItem
      }) => setActiveTab(selectedItem.index),
      initialSelectedItem: items?.[0],
      label: "tab selection",
      items: items,
      id: _id,
      className: withPrefix('tab-dropdown')
    })
  );
};
Select.propTypes = {
  _id: PropTypes.string.isRequired,
  children: PropTypes.oneOfType([PropTypes.element.isRequired, PropTypes.arrayOf(PropTypes.element.isRequired).isRequired]).isRequired
};

export { Select, Select as default };
